+import type { ReactNode } from 'react';
+
+interface SkillMarkdownProps {
+  content: string;
+}
+
+type MarkdownBlock =
+  | {
+      type: 'heading';
+      level: number;
+      text: string;
+    }
+  | {
+      type: 'paragraph';
+      text: string;
+    }
+  | {
+      type: 'list';
+      items: string[];
+    }
+  | {
+      type: 'quote';
+      text: string;
+    }
+  | {
+      type: 'code';
+      language: string;
+      code: string;
+    };
+
+function isMarkdownControlLine(line: string) {
+  return (
+    /^#{1,4}\s+/.test(line) ||
+    /^\s*[-*]\s+/.test(line) ||
+    /^>\s?/.test(line) ||
+    /^```/.test(line)
+  );
+}
+
+function parseMarkdown(content: string) {
+  const lines = content.split('\n');
+  const blocks: MarkdownBlock[] = [];
+  let index = 0;
+
+  while (index < lines.length) {
+    const line = lines[index] ?? '';
+    const trimmed = line.trim();
+
+    if (!trimmed) {
+      index += 1;
+      continue;
+    }
+
+    if (trimmed.startsWith('```')) {
+      const language = trimmed.replace(/^```/, '').trim();
+      const codeLines: string[] = [];
+      index += 1;
+
+      while (index < lines.length && !lines[index]?.trim().startsWith('```')) {
+        codeLines.push(lines[index] ?? '');
+        index += 1;
+      }
+
+      blocks.push({
+        type: 'code',
+        language,
+        code: codeLines.join('\n'),
+      });
+      index += 1;
+      continue;
+    }
+
+    const headingMatch = trimmed.match(/^(#{1,4})\s+(.+)$/);
+    if (headingMatch) {
+      blocks.push({
+        type: 'heading',
+        level: headingMatch[1].length,
+        text: headingMatch[2].trim(),
+      });
+      index += 1;
+      continue;
+    }
+
+    const bulletMatch = line.match(/^\s*[-*]\s+(.+)$/);
+    if (bulletMatch) {
+      const items: string[] = [];
+
+      while (index < lines.length) {
+        const currentBullet = lines[index]?.match(/^\s*[-*]\s+(.+)$/);
+        if (!currentBullet) {
+          break;
+        }
+
+        items.push(currentBullet[1].trim());
+        index += 1;
+      }
+
+      blocks.push({ type: 'list', items });
+      continue;
+    }
+
+    if (trimmed.startsWith('>')) {
+      const quoteLines: string[] = [];
+
+      while (index < lines.length) {
+        const current = lines[index] ?? '';
+        if (!current.trim().startsWith('>')) {
+          break;
+        }
+
+        quoteLines.push(current.replace(/^>\s?/, '').trim());
+        index += 1;
+      }
+
+      blocks.push({
+        type: 'quote',
+        text: quoteLines.join(' '),
+      });
+      continue;
+    }
+
+    const paragraphLines: string[] = [];
+
+    while (index < lines.length) {
+      const current = lines[index] ?? '';
+      if (!current.trim() || isMarkdownControlLine(current.trim())) {
+        break;
+      }
+
+      paragraphLines.push(current.trim());
+      index += 1;
+    }
+
+    blocks.push({
+      type: 'paragraph',
+      text: paragraphLines.join(' '),
+    });
+  }
+
+  return blocks;
+}
+
+function getSafeHref(href: string) {
+  if (/^(https?:\/\/|\/|#)/.test(href)) {
+    return href;
+  }
+
+  return '#';
+}
+
+function renderInline(value: string): ReactNode[] {
+  const parts = value.split(/(\*\*[^*]+\*\*|`[^`]+`|\[[^\]]+\]\([^)]+\))/g);
+
+  return parts.filter(Boolean).map((part, index) => {
+    if (part.startsWith('**') && part.endsWith('**')) {
+      return <strong key={index}>{renderInline(part.slice(2, -2))}</strong>;
+    }
+
+    if (part.startsWith('`') && part.endsWith('`')) {
+      return (
+        <code
+          key={index}
+          className="rounded bg-muted px-1 py-0.5 font-mono text-foreground text-[0.9em]"
+        >
+          {part.slice(1, -1)}
+        </code>
+      );
+    }
+
+    const linkMatch = part.match(/^\[([^\]]+)\]\(([^)]+)\)$/);
+    if (linkMatch) {
+      const href = getSafeHref(linkMatch[2]);
+      const isExternal = href.startsWith('http');
+
+      return (
+        <a
+          key={index}
+          href={href}
+          target={isExternal ? '_blank' : undefined}
+          rel={isExternal ? 'noreferrer' : undefined}
+          className="font-medium text-foreground underline underline-offset-4"
+        >
+          {linkMatch[1]}
+        </a>
+      );
+    }
+
+    return part;
+  });
+}
+
+function headingClassName(level: number) {
+  switch (level) {
+    case 1:
+      return 'text-3xl font-semibold tracking-tight text-foreground';
+    case 2:
+      return 'text-2xl font-semibold tracking-tight text-foreground';
+    case 3:
+      return 'text-xl font-semibold tracking-tight text-foreground';
+    default:
+      return 'text-lg font-semibold tracking-tight text-foreground';
+  }
+}
+
+export function SkillMarkdown({ content }: SkillMarkdownProps) {
+  const blocks = parseMarkdown(content);
+
+  return (
+    <div className="flex max-w-none flex-col gap-5">
+      {blocks.map((block, index) => {
+        if (block.type === 'heading') {
+          const HeadingTag = `h${Math.min(block.level, 4)}` as
+            | 'h1'
+            | 'h2'
+            | 'h3'
+            | 'h4';
+
+          return (
+            <HeadingTag
+              key={index}
+              className={headingClassName(block.level)}
+            >
+              {renderInline(block.text)}
+            </HeadingTag>
+          );
+        }
+
+        if (block.type === 'list') {
+          return (
+            <ul
+              key={index}
+              className="ml-5 flex list-disc flex-col gap-1 text-muted-foreground"
+            >
+              {block.items.map((item, itemIndex) => (
+                <li key={`${index}-${itemIndex}`}>{renderInline(item)}</li>
+              ))}
+            </ul>
+          );
+        }
+
+        if (block.type === 'quote') {
+          return (
+            <blockquote
+              key={index}
+              className="border-l pl-4 text-muted-foreground italic"
+            >
+              {renderInline(block.text)}
+            </blockquote>
+          );
+        }
+
+        if (block.type === 'code') {
+          return (
+            <pre
+              key={index}
+              className="overflow-x-auto rounded-md border bg-muted p-4 text-sm"
+            >
+              <code className="font-mono text-foreground">{block.code}</code>
+            </pre>
+          );
+        }
+
+        return (
+          <p key={index} className="leading-7 text-muted-foreground">
+            {renderInline(block.text)}
+          </p>
+        );
+      })}
+    </div>
+  );
+}
